import{_ as i,o as t,c as a,ai as r}from"./chunks/framework.C4ntERNc.js";const u=JSON.parse('{"title":"Contract","description":"","frontmatter":{"title":"Contract","lang":"en-US","layout":"doc","outline":"deep"},"headers":[],"relativePath":"getting-started/contract.md","filePath":"getting-started/contract.md"}'),n={name:"getting-started/contract.md"};function l(s,e,o,c,d,h){return t(),a("div",null,[...e[0]||(e[0]=[r('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /jz-hdl/getting-started/contract.md for this page in Markdown format</div><h1 id="contract" tabindex="-1">Contract <a class="header-anchor" href="#contract" aria-label="Permalink to “Contract”">​</a></h1><p>This document defines the <em>non-negotiable semantic contract</em> of JZ-HDL. If a design obeys these rules, it represents deterministic, synthesizable hardware. All other documents elaborate or provide syntax, but do not weaken or override this contract.</p><hr><h2 id="_1-execution-model" tabindex="-1">1. Execution Model <a class="header-anchor" href="#_1-execution-model" aria-label="Permalink to “1. Execution Model”">​</a></h2><p>JZ-HDL describes <strong>cycle-accurate hardware</strong>, not software execution.</p><ul><li><strong>ASYNCHRONOUS logic</strong> represents purely combinational hardware.</li><li><strong>SYNCHRONOUS logic</strong> represents edge-triggered storage updated by a clock.</li><li>There is no implicit ordering of statements; hardware exists concurrently.</li><li>All behavior must be explainable as wires, registers, memories, and gates.</li></ul><hr><h2 id="_2-nets-drivers-and-determinism" tabindex="-1">2. Nets, Drivers, and Determinism <a class="header-anchor" href="#_2-nets-drivers-and-determinism" aria-label="Permalink to “2. Nets, Drivers, and Determinism”">​</a></h2><h3 id="_2-1-drivers-and-sinks" tabindex="-1">2.1 Drivers and Sinks <a class="header-anchor" href="#_2-1-drivers-and-sinks" aria-label="Permalink to “2.1 Drivers and Sinks”">​</a></h3><ul><li>A <strong>driver</strong> actively assigns a value to a net.</li><li>A <strong>sink</strong> only reads a net.</li><li>The high-impedance state (<code>z</code>) is <em>not</em> an active driver.</li></ul><h3 id="_2-2-exclusive-assignment-rule" tabindex="-1">2.2 Exclusive Assignment Rule <a class="header-anchor" href="#_2-2-exclusive-assignment-rule" aria-label="Permalink to “2.2 Exclusive Assignment Rule”">​</a></h3><p>For every assignable identifier (wire, port, or register bit-range):</p><ul><li>In any single execution path, <strong>zero or one active driver</strong> may exist.</li><li>Multiple drivers are permitted only if: <ul><li>All but one drive <code>z</code> for every bit.</li></ul></li></ul><p>Violations are compile-time errors.</p><hr><h2 id="_3-combinational-correctness-asynchronous" tabindex="-1">3. Combinational Correctness (ASYNCHRONOUS) <a class="header-anchor" href="#_3-combinational-correctness-asynchronous" aria-label="Permalink to “3. Combinational Correctness (ASYNCHRONOUS)”">​</a></h2><ul><li>ASYNCHRONOUS logic must be <strong>fully deterministic</strong>.</li><li>Every net that is read must have a valid driver on every execution path.</li><li>Reading a net driven only by <code>z</code> is illegal.</li><li>Combinational loops are forbidden. <ul><li>Cycles that exist only in mutually exclusive paths are permitted.</li></ul></li></ul><p>There is no latch inference. Undriven paths are errors, not implied storage.</p><hr><h2 id="_4-sequential-correctness-synchronous" tabindex="-1">4. Sequential Correctness (SYNCHRONOUS) <a class="header-anchor" href="#_4-sequential-correctness-synchronous" aria-label="Permalink to “4. Sequential Correctness (SYNCHRONOUS)”">​</a></h2><h3 id="_4-1-registers" tabindex="-1">4.1 Registers <a class="header-anchor" href="#_4-1-registers" aria-label="Permalink to “4.1 Registers”">​</a></h3><ul><li>Registers are explicit storage elements.</li><li>Every register has: <ul><li>A current-value output</li><li>A next-state input</li><li>A mandatory reset value</li></ul></li></ul><h3 id="_4-2-clock-domains" tabindex="-1">4.2 Clock Domains <a class="header-anchor" href="#_4-2-clock-domains" aria-label="Permalink to “4.2 Clock Domains”">​</a></h3><ul><li>A module may contain <strong>at most one SYNCHRONOUS block per clock</strong>.</li><li>A register belongs to exactly one clock domain (its <em>Home Domain</em>).</li><li>A register may only be written in its Home Domain.</li><li>Registers may not be read or written from other clock domains directly.</li></ul><hr><h2 id="_5-reset-semantics" tabindex="-1">5. Reset Semantics <a class="header-anchor" href="#_5-reset-semantics" aria-label="Permalink to “5. Reset Semantics”">​</a></h2><ul><li>Reset has absolute priority over all logic.</li><li>Reset values are defined at register declaration.</li><li>Reset behavior is explicit: <ul><li>Polarity and timing (Immediate or Clocked) are defined by the block.</li></ul></li></ul><p>No implicit reset behavior exists.</p><hr><h2 id="_6-clock-domain-crossing-cdc" tabindex="-1">6. Clock Domain Crossing (CDC) <a class="header-anchor" href="#_6-clock-domain-crossing-cdc" aria-label="Permalink to “6. Clock Domain Crossing (CDC)”">​</a></h2><ul><li>All CDC behavior must be explicit.</li><li>Cross-domain access to registers is illegal without a CDC declaration.</li><li>CDC types define hardware structure: <ul><li>BIT: multi-flop synchronizer</li><li>BUS: encoded multi-bit crossing</li><li>FIFO: asynchronous queue</li></ul></li></ul><p>CDC is structural, not stylistic.</p><hr><h2 id="_7-assignment-semantics" tabindex="-1">7. Assignment Semantics <a class="header-anchor" href="#_7-assignment-semantics" aria-label="Permalink to “7. Assignment Semantics”">​</a></h2><h3 id="_7-1-no-implicit-width-conversion" tabindex="-1">7.1 No Implicit Width Conversion <a class="header-anchor" href="#_7-1-no-implicit-width-conversion" aria-label="Permalink to “7.1 No Implicit Width Conversion”">​</a></h3><ul><li>There is <strong>no implicit truncation</strong>.</li><li>There is <strong>no implicit extension</strong>.</li><li>All width changes must be explicit and intentional.</li></ul><h3 id="_7-2-path-exclusivity" tabindex="-1">7.2 Path Exclusivity <a class="header-anchor" href="#_7-2-path-exclusivity" aria-label="Permalink to “7.2 Path Exclusivity”">​</a></h3><ul><li>Assignments in independent conditional chains are not exclusive.</li><li>Assignments in mutually exclusive branches are exclusive.</li><li>Assignments that shadow or overlap in the same path are illegal.</li></ul><hr><h2 id="_8-arithmetic-and-data-integrity" tabindex="-1">8. Arithmetic and Data Integrity <a class="header-anchor" href="#_8-arithmetic-and-data-integrity" aria-label="Permalink to “8. Arithmetic and Data Integrity”">​</a></h2><ul><li>Arithmetic is width-defined and deterministic.</li><li>Overflow is never implicit.</li><li>Full-precision results must be explicitly captured.</li></ul><p>Data loss must be intentional and visible.</p><hr><h2 id="_9-memories" tabindex="-1">9. Memories <a class="header-anchor" href="#_9-memories" aria-label="Permalink to “9. Memories”">​</a></h2><ul><li>Memories represent true hardware storage arrays.</li><li>Read and write ports are explicit and typed.</li><li>Asynchronous and synchronous reads are distinct and enforced.</li><li>Writes are synchronous and deterministic.</li></ul><p>Memory behavior must match realizable silicon structures.</p><hr><h2 id="_10-what-jz-hdl-forbids-by-construction" tabindex="-1">10. What JZ-HDL Forbids by Construction <a class="header-anchor" href="#_10-what-jz-hdl-forbids-by-construction" aria-label="Permalink to “10. What JZ-HDL Forbids by Construction”">​</a></h2><p>JZ-HDL makes the following impossible:</p><ul><li>Accidental multiple drivers</li><li>Latch inference</li><li>Implicit CDC</li><li>Silent width truncation</li><li>Unclocked storage</li><li>Combinational oscillation</li><li>Ambiguous reset behavior</li></ul><p>If it compiles, the hardware is structurally sound.</p><hr><h2 id="_11-design-intent" tabindex="-1">11. Design Intent <a class="header-anchor" href="#_11-design-intent" aria-label="Permalink to “11. Design Intent”">​</a></h2><p>JZ-HDL prioritizes:</p><ul><li>Electrical correctness</li><li>Deterministic behavior</li><li>Auditability</li><li>Long-term maintainability</li></ul><p>Convenience is always secondary to correctness.</p><p>This contract is stable. All future extensions must preserve these rules.</p>',58)])])}const g=i(n,[["render",l]]);export{u as __pageData,g as default};
